// Функція для парсингу питань та відповідей
function parseQuestionsAndAnswers(inputData) {
  const results = [];

  // Отримуємо текст з input data
  let text = inputData[0].data;

  // Нормалізуємо текст - заміняємо різні види переносів на звичайні
  text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  // Знаходимо всі позиції "Питання:" та "Відповідь:"
  const questionMatches = [...text.matchAll(/Питання:\s*/g)];
  const answerMatches = [...text.matchAll(/Відповідь:\s*/g)];

  // Створюємо масив всіх маркерів з їх позиціями
  const markers = [];

  questionMatches.forEach(match => {
    markers.push({
      type: 'question',
      position: match.index + match[0].length,
      index: match.index
    });
  });

  answerMatches.forEach(match => {
    markers.push({
      type: 'answer',
      position: match.index + match[0].length,
      index: match.index
    });
  });

  // Сортуємо маркери по позиції
  markers.sort((a, b) => a.index - b.index);

  // Парсимо пари питання-відповідь
  let currentQuestion = '';
  let currentAnswer = '';
  let state = 'none';

  for (let i = 0; i < markers.length; i++) {
    const marker = markers[i];
    const nextMarker = markers[i + 1];

    if (marker.type === 'question') {
      if (state === 'answer' && currentQuestion && currentAnswer) {
        results.push({
          question: currentQuestion.trim(),
          answer: currentAnswer.trim()
        });
      }

      const endPos = nextMarker ? nextMarker.index : text.length;
      currentQuestion = text.substring(marker.position, endPos).trim();

      const answerInQuestion = currentQuestion.indexOf('Відповідь:');
      if (answerInQuestion !== -1) {
        currentQuestion = currentQuestion.substring(0, answerInQuestion).trim();
      }

      state = 'question';
      currentAnswer = '';

    } else if (marker.type === 'answer') {
      const endPos = nextMarker ? nextMarker.index : text.length;
      currentAnswer = text.substring(marker.position, endPos).trim();

      const questionInAnswer = currentAnswer.indexOf('Питання:');
      if (questionInAnswer !== -1) {
        currentAnswer = currentAnswer.substring(0, questionInAnswer).trim();
      }

      state = 'answer';

      if (currentQuestion && currentAnswer) {
        results.push({
          question: currentQuestion.trim(),
          answer: currentAnswer.trim()
        });
        currentQuestion = '';
        currentAnswer = '';
        state = 'none';
      }
    }
  }

  if (currentQuestion && currentAnswer) {
    results.push({
      question: currentQuestion.trim(),
      answer: currentAnswer.trim()
    });
  }

  return results;
}

